#include<bits/stdc++.h>
using namespace std;
int m,s,t,s1=0,t1=0,dp[300005][25];
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
    cin>>m>>s>>t;
    while(m>=10)
    {
        m-=10;
        t1++;
        s1+=60;
        if(s1>=s)
        {
            cout<<"Yes\n"<<t1;
            return 0;
        }
        if(t1==t)
        {
            cout<<"No\n"<<s1;
            return 0;
        }
    }
    memset(dp,128,sizeof(dp));
    t-=t1;
    s-=s1;
    dp[0][m]=0;
    int ans=-1;
    for(int i=1;i<=t;i++)
    {
        for(int j=0;j<=13;j++)
        {
            dp[i][j]=dp[i-1][j]+17;
            if(j<=3) dp[i][j]=max(dp[i-1][j+10]+60,dp[i][j]);
            if(j>=4) dp[i][j]=max(dp[i-1][j-4],dp[i][j]);
            if(dp[i][j]>s)
            {
                cout<<"Yes\n"<<i+t1;
                return 0;
            }
            if(i==t) ans=max(ans,dp[i][j]);
        }
    }
    cout<<"No\n"<<ans+s1;
    return 0;
}
